API_name: nchu_ge_course_search_by_type
Description:
{
  "description": "依通識類型（領域）查詢通識課程（人文、社會、自然、統合、核心素養等）。",
  "required_parameters": [
    {
      "name": "course_type",
      "type": "STRING",
      "description": "通識類型代碼或名稱（E=人文, F=社會, G=自然, K=統合, M=核心素養, L=資訊素養）"
    }
  ],
  "optional_parameters": [
    {
      "name": "semester",
      "type": "STRING",
      "description": "學年期代碼",
      "default": null
    }
  ]
}

